#include <iostream>
#include <string>
#include <vector>

class Enemy {
private:
    std::string name;
    int health;

public:
    Enemy(std::string n, int h) : name(n), health(h) {
        std::cout << "Enemy " << name << " created" << std::endl;
    }

    ~Enemy() {
        std::cout << "Enemy " << name << " destroyed" << std::endl;
    }

    void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }

    void takeDamage(int damage) {
        health -= damage;
        if (health < 0) health = 0;
    }
};

// --- BAD: Returning pointer to local variable ---
int* badReturn() {
    int local = 42;
    return &local;  // DANGER! local dies when function ends
}

// --- GOOD: Returning pointer to heap object ---
Enemy* createEnemy(const std::string& name, int health) {
    return new Enemy(name, health);  // Heap allocated → lives on
}

// --- GOOD: Returning pointer to static (use with caution) ---
int* getGlobalCounter() {
    static int counter = 0;
    counter++;
    return &counter;  // Safe: static lives forever
}

// --- BAD: Returning pointer to member of temporary ---
class Item {
public:
    std::string name;
    std::string* getNamePtr() { return &name; }
};

int* getTemporaryMember() {
    Item temp;
    temp.name = "Temporary";
    return temp.getNamePtr();  // DANGER! temp dies
}

// --- GOOD: Returning pointer to object passed in ---
Enemy* findEnemy(std::vector<Enemy*>& enemies, const std::string& name) {
    for (Enemy* e : enemies) {
        // Would need a way to get name
    }
    return nullptr;
}

int main() {
    std::cout << "=== Returning Pointers ===" << std::endl;

    // 1. Bad: returning pointer to local
    std::cout << "\n--- Bad: local variable ---" << std::endl;
    int* badPtr = badReturn();
    std::cout << "badPtr: " << *badPtr << " (undefined behavior!)" << std::endl;
    // This might print 42, it might print garbage, it might crash

    // 2. Good: returning pointer to heap
    std::cout << "\n--- Good: heap allocation ---" << std::endl;
    Enemy* goblin = createEnemy("Goblin", 30);
    goblin->display();
    delete goblin;  // Must delete!

    // 3. Good: returning pointer to static
    std::cout << "\n--- Good: static variable ---" << std::endl;
    int* counter1 = getGlobalCounter();
    int* counter2 = getGlobalCounter();
    std::cout << "Counter 1: " << *counter1 << std::endl;
    std::cout << "Counter 2: " << *counter2 << std::endl;

    // 4. Bad: returning pointer to member of temporary
    std::cout << "\n--- Bad: temporary member ---" << std::endl;
    int* tempPtr = getTemporaryMember();
    std::cout << "tempPtr: " << *tempPtr << " (undefined behavior!)" << std::endl;

    std::cout << "\n--- Rules for returning pointers ---" << std::endl;
    std::cout << "✅ Return heap objects (new)" << std::endl;
    std::cout << "✅ Return static variables" << std::endl;
    std::cout << "✅ Return pointers passed as parameters" << std::endl;
    std::cout << "❌ Return local variables" << std::endl;
    std::cout << "❌ Return members of temporaries" << std::endl;
    std::cout << "❌ Return nullptr without checking" << std::endl;

    return 0;
}

