#include <iostream>

int* createInt(int value) {
    int* ptr = new int(value);
    return ptr;
}

int* getStaticCounter() {
    static int counter = 0;
    counter++;
    return &counter;
}

int* findMax(int* a, int* b) {
    if (a == nullptr || b == nullptr) return nullptr;
    return (*a > *b) ? a : b;
}

int main() {
    // Heap allocation
    int* num = createInt(42);
    std::cout << "createInt(42): " << *num << std::endl;
    delete num;

    // Static counter
    int* c1 = getStaticCounter();
    int* c2 = getStaticCounter();
    std::cout << "Counter: " << *c1 << ", " << *c2 << std::endl;

    // Find max
    int x = 5, y = 10;
    int* max = findMax(&x, &y);
    if (max != nullptr) {
        std::cout << "Max of " << x << " and " << y << ": " << *max << std::endl;
    }

    return 0;
}
